module decoder2to4 (
  input [2-1:1-1] a,
  input enable,
  output reg [3:0] y);always_comb begin
		if (enable) begin
			case (a)
				2'b00: y = 4'b0001;
				2'b01: y = 4'b0010;
				2'b10: y = 4'b0100;
				2'b11: y = 4'b1000;
				default: y = 4'b0000;
			endcase
		end else
			y = 4'b0000;
	end

endmodule
